import { useState, useEffect } from "react";

const Handler = () => {
	// usestate for setting a javascript
	// object for storing and using data
	const [data, setData] = useState({
		grid: "",
		rows: "",
		cols: ""
	});


	// Using useEffect for single rendering
	useEffect(() => {
		// Using fetch to fetch the api from
		// flask server it will be redirected to proxy
		fetch("http://localhost:5000/data")
		.then((res) => res.json())
		.then((data) => {
				// Setting a data from api

				console.log(data.name)
				setData({
					grid: data.Grid,
					rows: data.Row_hints,
					cols: data.Col_hints

				});
			}
		);
	}, []);

	return (
		<div >
			<header>
				<p>React and flask</p>

				{/* Calling a data from setdata for showing */}
				<p>{data.grid}</p>
				<p>{data.rows}</p>
				<p>{data.cols}</p>
				<div>
				<div className="nonogram-grid-container">
      <table className="nonogram-grid">
        <tbody>
          {data.rows.map((rowHints, rowIndex) => (
            <tr key={`row-${rowIndex}`}>
              {rowHints.map((hint, hintIndex) => (
                <td key={`row-${rowIndex}-hint-${hintIndex}`} className="nonogram-hint nonogram-row-hint">{hint}</td>
              ))}
              {data.grid[rowIndex].map((cell, cellIndex) => (
                <td key={`row-${rowIndex}-cell-${cellIndex}`} className={`nonogram-cell ${cell === 1 ? 'filled' : ''}`} />
              ))}
            </tr>
          ))}
          <tr>
            {data.cols.map((colHints, colIndex) => (
              <td key={`col-${colIndex}-hint`} className="nonogram-hint nonogram-col-hint">{colHints.join(' ')}</td>
            ))}
          </tr>
        </tbody>
      </table>
    </div>
				</div>

			</header>
		</div>
	);
}

export default Handler;




